#!/usr/bin/env node
const fs = require('fs');
const path = require('path');
const root = process.cwd();
function ensureDir(p){fs.mkdirSync(path.dirname(p),{recursive:true});}
const files = {};
files["src/lib/rider-documents/getRiderDocumentsData.ts"] = "import { prisma } from \"@/lib/prisma\";\n\nexport type RiderDocumentFilters = {\n  q: string;\n  status: string;\n  verificationStatus: string;\n  type: string;\n  driverId: string;\n  expiry: string;\n};\n\nfunction first(value: string | string[] | undefined) {\n  return Array.isArray(value) ? value[0] : value;\n}\n\nfunction clean(value: unknown) {\n  return String(value ?? \"\").trim();\n}\n\nfunction toJson<T>(value: T): T {\n  return JSON.parse(JSON.stringify(value));\n}\n\nexport function resolveRiderDocumentFilters(params: Record<string, string | string[] | undefined> = {}): RiderDocumentFilters {\n  return {\n    q: clean(first(params.q)),\n    status: clean(first(params.status)),\n    verificationStatus: clean(first(params.verificationStatus)),\n    type: clean(first(params.type)),\n    driverId: clean(first(params.driverId)),\n    expiry: clean(first(params.expiry)),\n  };\n}\n\nfunction expiryWhere(expiry: string) {\n  const now = new Date();\n  const in30 = new Date(now);\n  in30.setDate(in30.getDate() + 30);\n  const in60 = new Date(now);\n  in60.setDate(in60.getDate() + 60);\n\n  if (expiry === \"expired\") return { expiryDate: { lt: now } };\n  if (expiry === \"30\") return { expiryDate: { gte: now, lte: in30 } };\n  if (expiry === \"60\") return { expiryDate: { gte: now, lte: in60 } };\n  if (expiry === \"missing\") return { expiryDate: null };\n  return {};\n}\n\nexport async function getRiderDocumentsData(filters: RiderDocumentFilters) {\n  const and: any[] = [];\n  if (filters.status) and.push({ status: filters.status });\n  if (filters.verificationStatus) and.push({ verificationStatus: filters.verificationStatus });\n  if (filters.type) and.push({ OR: [{ type: filters.type }, { documentType: filters.type }] });\n  if (filters.driverId) and.push({ driverId: filters.driverId });\n  if (filters.expiry) and.push(expiryWhere(filters.expiry));\n  if (filters.q) {\n    and.push({\n      OR: [\n        { type: { contains: filters.q, mode: \"insensitive\" } },\n        { documentType: { contains: filters.q, mode: \"insensitive\" } },\n        { documentNumber: { contains: filters.q, mode: \"insensitive\" } },\n        { notes: { contains: filters.q, mode: \"insensitive\" } },\n        { driver: { name: { contains: filters.q, mode: \"insensitive\" } } },\n        { driver: { actualName: { contains: filters.q, mode: \"insensitive\" } } },\n        { driver: { internalCode: { contains: filters.q, mode: \"insensitive\" } } },\n      ],\n    });\n  }\n\n  const where = and.length ? { AND: and } : {};\n\n  const [documents, drivers, counts] = await Promise.all([\n    prisma.driverDocument.findMany({\n      where,\n      include: {\n        driver: {\n          select: {\n            id: true,\n            internalCode: true,\n            name: true,\n            actualName: true,\n            phone: true,\n            city: { select: { id: true, nameAr: true, nameEn: true } },\n            project: { select: { id: true, name: true, nameAr: true, nameEn: true } },\n            supervisor: { select: { id: true, name: true } },\n          },\n        },\n      },\n      orderBy: [{ expiryDate: \"asc\" }, { createdAt: \"desc\" }],\n      take: 500,\n    }),\n    prisma.driver.findMany({\n      where: { status: { not: \"INACTIVE\" } },\n      select: {\n        id: true,\n        internalCode: true,\n        name: true,\n        actualName: true,\n        city: { select: { nameAr: true, nameEn: true } },\n      },\n      orderBy: [{ name: \"asc\" }],\n      take: 1000,\n    }),\n    prisma.driverDocument.groupBy({\n      by: [\"status\"],\n      _count: { _all: true },\n    }).catch(() => []),\n  ]);\n\n  const now = new Date();\n  const in30 = new Date(now);\n  in30.setDate(in30.getDate() + 30);\n\n  const expiringSoon = documents.filter((doc) => doc.expiryDate && doc.expiryDate >= now && doc.expiryDate <= in30).length;\n  const expired = documents.filter((doc) => doc.expiryDate && doc.expiryDate < now).length;\n  const pending = documents.filter((doc) => doc.status === \"PENDING\" || doc.verificationStatus === \"pending\").length;\n\n  return toJson({\n    filters,\n    documents,\n    drivers,\n    summary: {\n      total: documents.length,\n      expiringSoon,\n      expired,\n      pending,\n      approved: documents.filter((doc) => doc.status === \"APPROVED\" || doc.verificationStatus === \"verified\").length,\n      byStatus: counts,\n    },\n    documentTypes: [\n      { value: \"iqama\", label: \"\u0625\u0642\u0627\u0645\u0629\" },\n      { value: \"license\", label: \"\u0631\u062e\u0635\u0629 \u0642\u064a\u0627\u062f\u0629\" },\n      { value: \"contract\", label: \"\u0639\u0642\u062f\" },\n      { value: \"insurance\", label: \"\u062a\u0623\u0645\u064a\u0646\" },\n      { value: \"medical\", label: \"\u0643\u0634\u0641 \u0637\u0628\u064a\" },\n      { value: \"other\", label: \"\u0623\u062e\u0631\u0649\" },\n    ],\n  });\n}\n\nexport type RiderDocumentsData = Awaited<ReturnType<typeof getRiderDocumentsData>>;\n";
files["src/app/rider-documents/page.tsx"] = "import { RiderDocumentsClient } from \"@/components/rider-documents/RiderDocumentsClient\";\nimport { getRiderDocumentsData, resolveRiderDocumentFilters } from \"@/lib/rider-documents/getRiderDocumentsData\";\n\nexport const dynamic = \"force-dynamic\";\n\ntype PageProps = {\n  searchParams?: Promise<Record<string, string | string[] | undefined>>;\n};\n\nexport default async function RiderDocumentsPage({ searchParams }: PageProps) {\n  const filters = resolveRiderDocumentFilters((await searchParams) ?? {});\n  const data = await getRiderDocumentsData(filters);\n  return <RiderDocumentsClient data={data} />;\n}\n";
files["src/components/rider-documents/RiderDocumentsClient.tsx"] = "\"use client\";\n\nimport { useMemo, useState } from \"react\";\nimport type { RiderDocumentsData } from \"@/lib/rider-documents/getRiderDocumentsData\";\n\ntype DocumentRow = RiderDocumentsData[\"documents\"][number];\ntype DriverOption = RiderDocumentsData[\"drivers\"][number];\n\ntype FormState = {\n  id?: string;\n  driverId: string;\n  type: string;\n  documentType: string;\n  documentNumber: string;\n  issueDate: string;\n  expiryDate: string;\n  status: string;\n  verificationStatus: string;\n  fileUrl: string;\n  notes: string;\n};\n\nconst emptyForm: FormState = {\n  driverId: \"\",\n  type: \"iqama\",\n  documentType: \"\u0625\u0642\u0627\u0645\u0629\",\n  documentNumber: \"\",\n  issueDate: \"\",\n  expiryDate: \"\",\n  status: \"PENDING\",\n  verificationStatus: \"pending\",\n  fileUrl: \"\",\n  notes: \"\",\n};\n\nfunction fmt(value: string | Date | null | undefined) {\n  if (!value) return \"\u2014\";\n  const date = new Date(value);\n  if (Number.isNaN(date.getTime())) return \"\u2014\";\n  return date.toLocaleDateString(\"ar-SA\");\n}\n\nfunction toDateInput(value: string | Date | null | undefined) {\n  if (!value) return \"\";\n  const date = new Date(value);\n  if (Number.isNaN(date.getTime())) return \"\";\n  return date.toISOString().slice(0, 10);\n}\n\nfunction driverName(driver?: DocumentRow[\"driver\"] | DriverOption | null) {\n  if (!driver) return \"\u2014\";\n  return [driver.actualName, driver.name, \"internalCode\" in driver ? driver.internalCode : null].filter(Boolean).join(\" / \");\n}\n\nfunction statusLabel(status: string) {\n  const map: Record<string, string> = {\n    ACTIVE: \"\u0646\u0634\u0637\",\n    INACTIVE: \"\u063a\u064a\u0631 \u0646\u0634\u0637\",\n    PENDING: \"\u0645\u0639\u0644\u0651\u0642\",\n    APPROVED: \"\u0645\u0639\u062a\u0645\u062f\",\n    REJECTED: \"\u0645\u0631\u0641\u0648\u0636\",\n    CANCELLED: \"\u0645\u0644\u063a\u064a\",\n    LOCKED: \"\u0645\u0642\u0641\u0644\",\n  };\n  return map[status] || status;\n}\n\nfunction verificationLabel(value: string) {\n  const map: Record<string, string> = {\n    pending: \"\u0628\u0627\u0646\u062a\u0638\u0627\u0631 \u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629\",\n    verified: \"\u0645\u0648\u062b\u0642\",\n    rejected: \"\u0645\u0631\u0641\u0648\u0636\",\n    expired: \"\u0645\u0646\u062a\u0647\u064a\",\n  };\n  return map[value] || value || \"\u2014\";\n}\n\nfunction expiryTone(expiryDate?: string | Date | null) {\n  if (!expiryDate) return \"bg-slate-100 text-slate-700\";\n  const now = new Date();\n  const expiry = new Date(expiryDate);\n  const diff = Math.ceil((expiry.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));\n  if (diff < 0) return \"bg-red-100 text-red-700\";\n  if (diff <= 30) return \"bg-amber-100 text-amber-700\";\n  return \"bg-emerald-100 text-emerald-700\";\n}\n\nfunction expiryText(expiryDate?: string | Date | null) {\n  if (!expiryDate) return \"\u0628\u062f\u0648\u0646 \u062a\u0627\u0631\u064a\u062e\";\n  const now = new Date();\n  const expiry = new Date(expiryDate);\n  const diff = Math.ceil((expiry.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));\n  if (diff < 0) return `\u0645\u0646\u062a\u0647\u064a \u0645\u0646\u0630 ${Math.abs(diff)} \u064a\u0648\u0645`;\n  if (diff === 0) return \"\u064a\u0646\u062a\u0647\u064a \u0627\u0644\u064a\u0648\u0645\";\n  return `\u0645\u062a\u0628\u0642\u064a ${diff} \u064a\u0648\u0645`;\n}\n\nfunction csvEscape(value: unknown) {\n  const text = String(value ?? \"\").replace(/\"/g, '\"\"');\n  return `\"${text}\"`;\n}\n\nexport function RiderDocumentsClient({ data }: { data: RiderDocumentsData }) {\n  const [form, setForm] = useState<FormState | null>(null);\n  const [saving, setSaving] = useState(false);\n  const [error, setError] = useState(\"\");\n\n  const selectedDriver = useMemo(() => data.drivers.find((driver) => driver.id === form?.driverId), [data.drivers, form?.driverId]);\n\n  function openCreate() {\n    setError(\"\");\n    setForm({ ...emptyForm });\n  }\n\n  function openEdit(row: DocumentRow) {\n    setError(\"\");\n    setForm({\n      id: row.id,\n      driverId: row.driverId,\n      type: row.type || row.documentType || \"other\",\n      documentType: row.documentType || row.type || \"\",\n      documentNumber: row.documentNumber || \"\",\n      issueDate: toDateInput(row.issueDate),\n      expiryDate: toDateInput(row.expiryDate),\n      status: row.status || \"PENDING\",\n      verificationStatus: row.verificationStatus || \"pending\",\n      fileUrl: row.fileUrl || \"\",\n      notes: row.notes || \"\",\n    });\n  }\n\n  async function saveForm(event: React.FormEvent) {\n    event.preventDefault();\n    if (!form) return;\n    if (!form.driverId) {\n      setError(\"\u0627\u062e\u062a\u0627\u0631 \u0627\u0644\u0645\u0646\u062f\u0648\u0628 \u0623\u0648\u0644\u064b\u0627.\");\n      return;\n    }\n    setSaving(true);\n    setError(\"\");\n    const method = form.id ? \"PATCH\" : \"POST\";\n    const url = form.id ? `/api/rider-documents/${form.id}` : \"/api/rider-documents\";\n    const res = await fetch(url, {\n      method,\n      headers: { \"content-type\": \"application/json\" },\n      body: JSON.stringify(form),\n    });\n    const payload = await res.json().catch(() => null);\n    setSaving(false);\n    if (!res.ok) {\n      setError(payload?.error || \"\u062a\u0639\u0630\u0631 \u062d\u0641\u0638 \u0627\u0644\u0645\u0633\u062a\u0646\u062f.\");\n      return;\n    }\n    window.location.reload();\n  }\n\n  async function patchRow(row: DocumentRow, updates: Partial<FormState>) {\n    const res = await fetch(`/api/rider-documents/${row.id}`, {\n      method: \"PATCH\",\n      headers: { \"content-type\": \"application/json\" },\n      body: JSON.stringify(updates),\n    });\n    if (!res.ok) {\n      const payload = await res.json().catch(() => null);\n      alert(payload?.error || \"\u062a\u0639\u0630\u0631 \u062a\u062d\u062f\u064a\u062b \u0627\u0644\u0645\u0633\u062a\u0646\u062f.\");\n      return;\n    }\n    window.location.reload();\n  }\n\n  async function deleteRow(row: DocumentRow) {\n    if (!confirm(`\u062d\u0630\u0641 \u0645\u0633\u062a\u0646\u062f ${row.documentType || row.type}\u061f`)) return;\n    const res = await fetch(`/api/rider-documents/${row.id}`, { method: \"DELETE\" });\n    if (!res.ok) {\n      const payload = await res.json().catch(() => null);\n      alert(payload?.error || \"\u062a\u0639\u0630\u0631 \u062d\u0630\u0641 \u0627\u0644\u0645\u0633\u062a\u0646\u062f.\");\n      return;\n    }\n    window.location.reload();\n  }\n\n  function downloadCsv() {\n    const headers = [\"\u0627\u0644\u0645\u0646\u062f\u0648\u0628\", \"\u0627\u0644\u0643\u0648\u062f\", \"\u0627\u0644\u0646\u0648\u0639\", \"\u0627\u0644\u0631\u0642\u0645\", \"\u0627\u0644\u0625\u0635\u062f\u0627\u0631\", \"\u0627\u0644\u0627\u0646\u062a\u0647\u0627\u0621\", \"\u0627\u0644\u062d\u0627\u0644\u0629\", \"\u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629\", \"\u0645\u0644\u0627\u062d\u0638\u0627\u062a\"];\n    const rows = data.documents.map((row) => [\n      driverName(row.driver),\n      row.driver?.internalCode,\n      row.documentType || row.type,\n      row.documentNumber,\n      fmt(row.issueDate),\n      fmt(row.expiryDate),\n      statusLabel(row.status),\n      verificationLabel(row.verificationStatus),\n      row.notes,\n    ]);\n    const csv = [headers, ...rows].map((row) => row.map(csvEscape).join(\",\")).join(\"\\n\");\n    const blob = new Blob([\"\\uFEFF\" + csv], { type: \"text/csv;charset=utf-8\" });\n    const url = URL.createObjectURL(blob);\n    const a = document.createElement(\"a\");\n    a.href = url;\n    a.download = `rider-documents-${new Date().toISOString().slice(0, 10)}.csv`;\n    a.click();\n    URL.revokeObjectURL(url);\n  }\n\n  return (\n    <main className=\"min-h-screen bg-slate-50 p-4 text-slate-950 md:p-6\" dir=\"rtl\" suppressHydrationWarning>\n      <header className=\"mb-4 flex flex-col gap-3 rounded-3xl border border-slate-200 bg-white p-4 shadow-sm md:flex-row md:items-center md:justify-between\">\n        <div>\n          <p className=\"text-xs font-black text-blue-600\">\u0627\u0644\u0645\u0648\u0627\u0631\u062f \u0627\u0644\u0628\u0634\u0631\u064a\u0629</p>\n          <h1 className=\"text-2xl font-black\">\u0645\u0633\u062a\u0646\u062f\u0627\u062a \u0627\u0644\u0645\u0646\u0627\u062f\u064a\u0628</h1>\n          <p className=\"mt-1 text-sm text-slate-500\">\u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u0625\u0642\u0627\u0645\u0627\u062a \u0648\u0627\u0644\u0631\u062e\u0635 \u0648\u0627\u0644\u0639\u0642\u0648\u062f \u0648\u0627\u0644\u062a\u0646\u0628\u064a\u0647\u0627\u062a \u0642\u0628\u0644 \u0627\u0644\u0627\u0646\u062a\u0647\u0627\u0621.</p>\n        </div>\n        <div className=\"flex flex-wrap gap-2\">\n          <button type=\"button\" onClick={() => history.back()} className=\"rounded-xl border border-slate-200 bg-white px-4 py-2 text-sm font-black hover:bg-slate-50\">\u0631\u062c\u0648\u0639</button>\n          <button type=\"button\" onClick={() => window.print()} className=\"rounded-xl border border-slate-200 bg-white px-4 py-2 text-sm font-black hover:bg-slate-50\">\u0637\u0628\u0627\u0639\u0629 / PDF</button>\n          <button type=\"button\" onClick={downloadCsv} className=\"rounded-xl border border-amber-200 bg-amber-50 px-4 py-2 text-sm font-black text-amber-700 hover:bg-amber-100\">\u062a\u0635\u062f\u064a\u0631 \u0625\u0643\u0633\u0644</button>\n          <button type=\"button\" onClick={openCreate} className=\"rounded-xl bg-emerald-600 px-4 py-2 text-sm font-black text-white shadow-sm hover:bg-emerald-700\">+ \u0625\u0636\u0627\u0641\u0629 \u0645\u0633\u062a\u0646\u062f</button>\n        </div>\n      </header>\n\n      <section className=\"mb-4 grid gap-3 md:grid-cols-5\">\n        <SummaryCard title=\"\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u0645\u0633\u062a\u0646\u062f\u0627\u062a\" value={data.summary.total} />\n        <SummaryCard title=\"\u0628\u0627\u0646\u062a\u0638\u0627\u0631 \u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629\" value={data.summary.pending} tone=\"amber\" />\n        <SummaryCard title=\"\u0645\u0648\u062b\u0642\u0629 / \u0645\u0639\u062a\u0645\u062f\u0629\" value={data.summary.approved} tone=\"green\" />\n        <SummaryCard title=\"\u062a\u0646\u062a\u0647\u064a \u062e\u0644\u0627\u0644 30 \u064a\u0648\u0645\" value={data.summary.expiringSoon} tone=\"orange\" />\n        <SummaryCard title=\"\u0645\u0646\u062a\u0647\u064a\u0629\" value={data.summary.expired} tone=\"red\" />\n      </section>\n\n      <section className=\"mb-4 rounded-3xl border border-slate-200 bg-white p-4 shadow-sm\">\n        <form action=\"/rider-documents\" className=\"grid gap-3 md:grid-cols-7\">\n          <label className=\"text-xs font-black text-slate-600 md:col-span-2\">\n            \u0628\u062d\u062b\n            <input name=\"q\" defaultValue={data.filters.q} placeholder=\"\u0645\u0646\u062f\u0648\u0628 / \u0643\u0648\u062f / \u0631\u0642\u0645 \u0645\u0633\u062a\u0646\u062f\" className=\"mt-1 h-10 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm outline-none focus:border-blue-400\" />\n          </label>\n          <label className=\"text-xs font-black text-slate-600\">\n            \u0627\u0644\u0646\u0648\u0639\n            <select name=\"type\" defaultValue={data.filters.type} className=\"mt-1 h-10 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\">\n              <option value=\"\">\u0627\u0644\u0643\u0644</option>\n              {data.documentTypes.map((item) => <option key={item.value} value={item.value}>{item.label}</option>)}\n            </select>\n          </label>\n          <label className=\"text-xs font-black text-slate-600\">\n            \u0627\u0644\u062d\u0627\u0644\u0629\n            <select name=\"status\" defaultValue={data.filters.status} className=\"mt-1 h-10 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\">\n              <option value=\"\">\u0627\u0644\u0643\u0644</option>\n              <option value=\"PENDING\">\u0645\u0639\u0644\u0651\u0642</option>\n              <option value=\"APPROVED\">\u0645\u0639\u062a\u0645\u062f</option>\n              <option value=\"REJECTED\">\u0645\u0631\u0641\u0648\u0636</option>\n              <option value=\"ACTIVE\">\u0646\u0634\u0637</option>\n              <option value=\"CANCELLED\">\u0645\u0644\u063a\u064a</option>\n            </select>\n          </label>\n          <label className=\"text-xs font-black text-slate-600\">\n            \u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629\n            <select name=\"verificationStatus\" defaultValue={data.filters.verificationStatus} className=\"mt-1 h-10 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\">\n              <option value=\"\">\u0627\u0644\u0643\u0644</option>\n              <option value=\"pending\">\u0628\u0627\u0646\u062a\u0638\u0627\u0631</option>\n              <option value=\"verified\">\u0645\u0648\u062b\u0642</option>\n              <option value=\"rejected\">\u0645\u0631\u0641\u0648\u0636</option>\n              <option value=\"expired\">\u0645\u0646\u062a\u0647\u064a</option>\n            </select>\n          </label>\n          <label className=\"text-xs font-black text-slate-600\">\n            \u0627\u0644\u0627\u0646\u062a\u0647\u0627\u0621\n            <select name=\"expiry\" defaultValue={data.filters.expiry} className=\"mt-1 h-10 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\">\n              <option value=\"\">\u0627\u0644\u0643\u0644</option>\n              <option value=\"30\">\u062e\u0644\u0627\u0644 30 \u064a\u0648\u0645</option>\n              <option value=\"60\">\u062e\u0644\u0627\u0644 60 \u064a\u0648\u0645</option>\n              <option value=\"expired\">\u0645\u0646\u062a\u0647\u064a</option>\n              <option value=\"missing\">\u0628\u062f\u0648\u0646 \u062a\u0627\u0631\u064a\u062e</option>\n            </select>\n          </label>\n          <div className=\"flex items-end gap-2\">\n            <button type=\"submit\" className=\"h-10 flex-1 rounded-xl bg-slate-950 px-4 text-sm font-black text-white\">\u062a\u0637\u0628\u064a\u0642</button>\n            <button type=\"button\" onClick={() => (window.location.href = \"/rider-documents\")} className=\"h-10 flex-1 rounded-xl border border-slate-200 bg-white px-4 text-sm font-black\">\u0639\u0631\u0636 \u0627\u0644\u0643\u0644</button>\n          </div>\n        </form>\n      </section>\n\n      <section className=\"overflow-hidden rounded-3xl border border-slate-200 bg-white shadow-sm\">\n        <div className=\"overflow-x-auto\">\n          <table className=\"min-w-[1200px] w-full text-right text-sm\">\n            <thead className=\"bg-slate-100 text-xs font-black text-slate-600\">\n              <tr>\n                <th className=\"px-3 py-3\">\u0627\u0644\u0645\u0646\u062f\u0648\u0628</th>\n                <th className=\"px-3 py-3\">\u0627\u0644\u0645\u062f\u064a\u0646\u0629 / \u0627\u0644\u0645\u0634\u0631\u0648\u0639</th>\n                <th className=\"px-3 py-3\">\u0646\u0648\u0639 \u0627\u0644\u0645\u0633\u062a\u0646\u062f</th>\n                <th className=\"px-3 py-3\">\u0631\u0642\u0645 \u0627\u0644\u0645\u0633\u062a\u0646\u062f</th>\n                <th className=\"px-3 py-3\">\u0627\u0644\u0625\u0635\u062f\u0627\u0631</th>\n                <th className=\"px-3 py-3\">\u0627\u0644\u0627\u0646\u062a\u0647\u0627\u0621</th>\n                <th className=\"px-3 py-3\">\u0627\u0644\u062d\u0627\u0644\u0629</th>\n                <th className=\"px-3 py-3\">\u0627\u0644\u0645\u0631\u0627\u062c\u0639\u0629</th>\n                <th className=\"px-3 py-3\">\u0627\u0644\u0645\u0644\u0641</th>\n                <th className=\"sticky left-0 bg-slate-100 px-3 py-3\">\u0625\u062c\u0631\u0627\u0621\u0627\u062a</th>\n              </tr>\n            </thead>\n            <tbody className=\"divide-y divide-slate-100\">\n              {data.documents.length === 0 ? (\n                <tr><td colSpan={10} className=\"px-3 py-10 text-center text-slate-500\">\u0644\u0627 \u062a\u0648\u062c\u062f \u0645\u0633\u062a\u0646\u062f\u0627\u062a \u0645\u0637\u0627\u0628\u0642\u0629 \u0644\u0644\u0641\u0644\u0627\u062a\u0631 \u0627\u0644\u062d\u0627\u0644\u064a\u0629.</td></tr>\n              ) : data.documents.map((row) => (\n                <tr key={row.id} className=\"hover:bg-slate-50\">\n                  <td className=\"px-3 py-3 font-black\">\n                    {driverName(row.driver)}\n                    <div className=\"text-xs font-bold text-slate-400\">{row.driver?.phone || \"\u2014\"}</div>\n                  </td>\n                  <td className=\"px-3 py-3 text-slate-600\">\n                    {row.driver?.city?.nameAr || row.driver?.city?.nameEn || \"\u2014\"}\n                    <div className=\"text-xs text-slate-400\">{row.driver?.project?.nameAr || row.driver?.project?.name || \"\u2014\"}</div>\n                  </td>\n                  <td className=\"px-3 py-3 font-bold\">{row.documentType || row.type}</td>\n                  <td className=\"px-3 py-3\">{row.documentNumber || \"\u2014\"}</td>\n                  <td className=\"px-3 py-3\">{fmt(row.issueDate)}</td>\n                  <td className=\"px-3 py-3\">\n                    <span className={`inline-flex rounded-full px-2 py-1 text-xs font-black ${expiryTone(row.expiryDate)}`}>{expiryText(row.expiryDate)}</span>\n                    <div className=\"mt-1 text-xs text-slate-400\">{fmt(row.expiryDate)}</div>\n                  </td>\n                  <td className=\"px-3 py-3\"><span className=\"rounded-full bg-slate-100 px-2 py-1 text-xs font-black text-slate-700\">{statusLabel(row.status)}</span></td>\n                  <td className=\"px-3 py-3\"><span className=\"rounded-full bg-blue-50 px-2 py-1 text-xs font-black text-blue-700\">{verificationLabel(row.verificationStatus)}</span></td>\n                  <td className=\"px-3 py-3\">{row.fileUrl ? <a href={row.fileUrl} target=\"_blank\" className=\"font-black text-blue-700 underline\">\u0641\u062a\u062d \u0627\u0644\u0645\u0644\u0641</a> : \"\u2014\"}</td>\n                  <td className=\"sticky left-0 bg-white px-3 py-3 shadow-[-6px_0_12px_rgba(15,23,42,0.06)]\">\n                    <div className=\"flex flex-wrap gap-1\">\n                      <button type=\"button\" onClick={() => openEdit(row)} className=\"rounded-lg bg-blue-600 px-3 py-1.5 text-xs font-black text-white\">\u062a\u0639\u062f\u064a\u0644</button>\n                      <button type=\"button\" onClick={() => patchRow(row, { status: \"APPROVED\", verificationStatus: \"verified\" })} className=\"rounded-lg bg-emerald-600 px-3 py-1.5 text-xs font-black text-white\">\u0627\u0639\u062a\u0645\u0627\u062f</button>\n                      <button type=\"button\" onClick={() => patchRow(row, { status: \"REJECTED\", verificationStatus: \"rejected\" })} className=\"rounded-lg bg-amber-500 px-3 py-1.5 text-xs font-black text-white\">\u0631\u0641\u0636</button>\n                      <button type=\"button\" onClick={() => deleteRow(row)} className=\"rounded-lg bg-red-600 px-3 py-1.5 text-xs font-black text-white\">\u062d\u0630\u0641</button>\n                    </div>\n                  </td>\n                </tr>\n              ))}\n            </tbody>\n          </table>\n        </div>\n      </section>\n\n      {form && (\n        <div className=\"fixed inset-0 z-50 flex items-center justify-center bg-slate-950/50 p-4\">\n          <form onSubmit={saveForm} className=\"max-h-[90vh] w-full max-w-3xl overflow-y-auto rounded-3xl bg-white p-5 shadow-2xl\">\n            <div className=\"mb-4 flex items-center justify-between gap-3\">\n              <h2 className=\"text-xl font-black\">{form.id ? \"\u062a\u0639\u062f\u064a\u0644 \u0645\u0633\u062a\u0646\u062f\" : \"\u0625\u0636\u0627\u0641\u0629 \u0645\u0633\u062a\u0646\u062f\"}</h2>\n              <button type=\"button\" onClick={() => setForm(null)} className=\"rounded-xl border border-slate-200 px-3 py-2 text-sm font-black\">\u0625\u063a\u0644\u0627\u0642</button>\n            </div>\n            {error ? <div className=\"mb-3 rounded-xl border border-red-200 bg-red-50 px-3 py-2 text-sm font-black text-red-700\">{error}</div> : null}\n            <div className=\"grid gap-3 md:grid-cols-2\">\n              <label className=\"text-xs font-black text-slate-600 md:col-span-2\">\n                \u0627\u0644\u0645\u0646\u062f\u0648\u0628\n                <select value={form.driverId} onChange={(e) => setForm({ ...form, driverId: e.target.value })} className=\"mt-1 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\" required>\n                  <option value=\"\">\u0627\u062e\u062a\u0627\u0631 \u0627\u0644\u0645\u0646\u062f\u0648\u0628</option>\n                  {data.drivers.map((driver) => <option key={driver.id} value={driver.id}>{driverName(driver)}</option>)}\n                </select>\n              </label>\n              <div className=\"rounded-2xl bg-slate-50 p-3 text-xs text-slate-500 md:col-span-2\">\n                \u0627\u0644\u0645\u0646\u062f\u0648\u0628 \u0627\u0644\u0645\u062e\u062a\u0627\u0631: <span className=\"font-black text-slate-800\">{driverName(selectedDriver)}</span>\n              </div>\n              <label className=\"text-xs font-black text-slate-600\">\n                \u0643\u0648\u062f \u0627\u0644\u0646\u0648\u0639\n                <select value={form.type} onChange={(e) => setForm({ ...form, type: e.target.value, documentType: data.documentTypes.find((item) => item.value === e.target.value)?.label || form.documentType })} className=\"mt-1 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\">\n                  {data.documentTypes.map((item) => <option key={item.value} value={item.value}>{item.label}</option>)}\n                </select>\n              </label>\n              <label className=\"text-xs font-black text-slate-600\">\n                \u0627\u0633\u0645 \u0627\u0644\u0645\u0633\u062a\u0646\u062f\n                <input value={form.documentType} onChange={(e) => setForm({ ...form, documentType: e.target.value })} className=\"mt-1 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\" />\n              </label>\n              <label className=\"text-xs font-black text-slate-600\">\n                \u0631\u0642\u0645 \u0627\u0644\u0645\u0633\u062a\u0646\u062f\n                <input value={form.documentNumber} onChange={(e) => setForm({ ...form, documentNumber: e.target.value })} className=\"mt-1 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\" />\n              </label>\n              <label className=\"text-xs font-black text-slate-600\">\n                \u0631\u0627\u0628\u0637 \u0627\u0644\u0645\u0644\u0641\n                <input value={form.fileUrl} onChange={(e) => setForm({ ...form, fileUrl: e.target.value })} placeholder=\"https://...\" className=\"mt-1 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\" />\n              </label>\n              <label className=\"text-xs font-black text-slate-600\">\n                \u062a\u0627\u0631\u064a\u062e \u0627\u0644\u0625\u0635\u062f\u0627\u0631\n                <input type=\"date\" value={form.issueDate} onChange={(e) => setForm({ ...form, issueDate: e.target.value })} className=\"mt-1 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\" />\n              </label>\n              <label className=\"text-xs font-black text-slate-600\">\n                \u062a\u0627\u0631\u064a\u062e \u0627\u0644\u0627\u0646\u062a\u0647\u0627\u0621\n                <input type=\"date\" value={form.expiryDate} onChange={(e) => setForm({ ...form, expiryDate: e.target.value })} className=\"mt-1 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\" />\n              </label>\n              <label className=\"text-xs font-black text-slate-600\">\n                \u0627\u0644\u062d\u0627\u0644\u0629\n                <select value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value })} className=\"mt-1 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\">\n                  <option value=\"PENDING\">\u0645\u0639\u0644\u0651\u0642</option>\n                  <option value=\"APPROVED\">\u0645\u0639\u062a\u0645\u062f</option>\n                  <option value=\"REJECTED\">\u0645\u0631\u0641\u0648\u0636</option>\n                  <option value=\"ACTIVE\">\u0646\u0634\u0637</option>\n                  <option value=\"CANCELLED\">\u0645\u0644\u063a\u064a</option>\n                </select>\n              </label>\n              <label className=\"text-xs font-black text-slate-600\">\n                \u0645\u0631\u0627\u062c\u0639\u0629 \u0627\u0644\u0645\u0644\u0641\n                <select value={form.verificationStatus} onChange={(e) => setForm({ ...form, verificationStatus: e.target.value })} className=\"mt-1 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm\">\n                  <option value=\"pending\">\u0628\u0627\u0646\u062a\u0638\u0627\u0631</option>\n                  <option value=\"verified\">\u0645\u0648\u062b\u0642</option>\n                  <option value=\"rejected\">\u0645\u0631\u0641\u0648\u0636</option>\n                  <option value=\"expired\">\u0645\u0646\u062a\u0647\u064a</option>\n                </select>\n              </label>\n              <label className=\"text-xs font-black text-slate-600 md:col-span-2\">\n                \u0645\u0644\u0627\u062d\u0638\u0627\u062a\n                <textarea value={form.notes} onChange={(e) => setForm({ ...form, notes: e.target.value })} rows={3} className=\"mt-1 w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm\" />\n              </label>\n            </div>\n            <div className=\"mt-5 flex justify-end gap-2\">\n              <button type=\"button\" onClick={() => setForm(null)} className=\"rounded-xl border border-slate-200 bg-white px-5 py-2 text-sm font-black\">\u0625\u0644\u063a\u0627\u0621</button>\n              <button type=\"submit\" disabled={saving} className=\"rounded-xl bg-slate-950 px-5 py-2 text-sm font-black text-white disabled:opacity-60\">{saving ? \"\u062c\u0627\u0631\u064a \u0627\u0644\u062d\u0641\u0638...\" : \"\u062d\u0641\u0638\"}</button>\n            </div>\n          </form>\n        </div>\n      )}\n    </main>\n  );\n}\n\nfunction SummaryCard({ title, value, tone = \"slate\" }: { title: string; value: number; tone?: \"slate\" | \"amber\" | \"green\" | \"orange\" | \"red\" }) {\n  const cls: Record<string, string> = {\n    slate: \"bg-white text-slate-950 border-slate-200\",\n    amber: \"bg-amber-50 text-amber-700 border-amber-200\",\n    green: \"bg-emerald-50 text-emerald-700 border-emerald-200\",\n    orange: \"bg-orange-50 text-orange-700 border-orange-200\",\n    red: \"bg-red-50 text-red-700 border-red-200\",\n  };\n  return (\n    <div className={`rounded-3xl border p-4 shadow-sm ${cls[tone]}`}>\n      <p className=\"text-xs font-black opacity-70\">{title}</p>\n      <p className=\"mt-2 text-3xl font-black\">{value}</p>\n    </div>\n  );\n}\n";
files["src/app/api/rider-documents/route.ts"] = "import { NextResponse } from \"next/server\";\nimport { prisma } from \"@/lib/prisma\";\nimport { canReadResource, canWriteResource, roleFromHeaders } from \"@/lib/permissions\";\n\nfunction text(value: unknown) {\n  return String(value ?? \"\").trim();\n}\n\nfunction nullableText(value: unknown) {\n  const raw = text(value);\n  return raw || null;\n}\n\nfunction parseDate(value: unknown) {\n  const raw = text(value);\n  if (!raw) return null;\n  const date = new Date(raw);\n  return Number.isNaN(date.getTime()) ? null : date;\n}\n\nfunction recordStatus(value: unknown) {\n  const raw = text(value).toUpperCase();\n  if ([\"ACTIVE\", \"INACTIVE\", \"PENDING\", \"APPROVED\", \"REJECTED\", \"LOCKED\", \"CANCELLED\", \"DEDUCTED\", \"PARTIALLY_DEDUCTED\"].includes(raw)) return raw;\n  return \"PENDING\";\n}\n\nfunction serialize(value: unknown) {\n  return JSON.parse(JSON.stringify(value ?? null));\n}\n\nasync function canRead(request: Request) {\n  const role = roleFromHeaders(request.headers);\n  return canReadResource(role, \"driver-documents\") || canReadResource(role, \"drivers\");\n}\n\nasync function canWrite(request: Request) {\n  const role = roleFromHeaders(request.headers);\n  return canWriteResource(role, \"driver-documents\") || canWriteResource(role, \"drivers\");\n}\n\nexport async function GET(request: Request) {\n  if (!(await canRead(request))) return NextResponse.json({ error: \"Forbidden\" }, { status: 403 });\n  const url = new URL(request.url);\n  const q = text(url.searchParams.get(\"q\"));\n  const status = text(url.searchParams.get(\"status\"));\n  const driverId = text(url.searchParams.get(\"driverId\"));\n  const where: any = {};\n  if (status) where.status = status;\n  if (driverId) where.driverId = driverId;\n  if (q) {\n    where.OR = [\n      { type: { contains: q, mode: \"insensitive\" } },\n      { documentType: { contains: q, mode: \"insensitive\" } },\n      { documentNumber: { contains: q, mode: \"insensitive\" } },\n      { driver: { name: { contains: q, mode: \"insensitive\" } } },\n      { driver: { actualName: { contains: q, mode: \"insensitive\" } } },\n      { driver: { internalCode: { contains: q, mode: \"insensitive\" } } },\n    ];\n  }\n  const documents = await prisma.driverDocument.findMany({\n    where,\n    include: { driver: { select: { id: true, name: true, actualName: true, internalCode: true } } },\n    orderBy: { createdAt: \"desc\" },\n    take: 500,\n  });\n  return NextResponse.json({ documents: serialize(documents) });\n}\n\nexport async function POST(request: Request) {\n  if (!(await canWrite(request))) return NextResponse.json({ error: \"Forbidden\" }, { status: 403 });\n  const body = await request.json().catch(() => ({}));\n  const driverId = text(body.driverId);\n  const type = text(body.type) || text(body.documentType) || \"other\";\n  if (!driverId) return NextResponse.json({ error: \"\u0627\u0644\u0645\u0646\u062f\u0648\u0628 \u0645\u0637\u0644\u0648\u0628.\" }, { status: 400 });\n  const driver = await prisma.driver.findUnique({ where: { id: driverId }, select: { id: true } });\n  if (!driver) return NextResponse.json({ error: \"\u0627\u0644\u0645\u0646\u062f\u0648\u0628 \u063a\u064a\u0631 \u0645\u0648\u062c\u0648\u062f.\" }, { status: 404 });\n\n  const document = await prisma.driverDocument.create({\n    data: {\n      driverId,\n      type,\n      documentType: nullableText(body.documentType) || type,\n      documentNumber: nullableText(body.documentNumber),\n      issueDate: parseDate(body.issueDate),\n      expiryDate: parseDate(body.expiryDate),\n      status: recordStatus(body.status) as any,\n      verificationStatus: text(body.verificationStatus) || \"pending\",\n      fileUrl: nullableText(body.fileUrl),\n      notes: nullableText(body.notes),\n    },\n    include: { driver: { select: { id: true, name: true, actualName: true, internalCode: true } } },\n  });\n\n  await prisma.auditLog.create({\n    data: {\n      user: request.headers.get(\"x-user-email\") || undefined,\n      action: \"CREATE_DRIVER_DOCUMENT\",\n      entityType: \"DriverDocument\",\n      entityId: document.id,\n      newValue: serialize(document),\n    },\n  }).catch(() => null);\n\n  return NextResponse.json({ document: serialize(document) }, { status: 201 });\n}\n";
files["src/app/api/rider-documents/[id]/route.ts"] = "import { NextResponse } from \"next/server\";\nimport { prisma } from \"@/lib/prisma\";\nimport { canReadResource, canWriteResource, roleFromHeaders } from \"@/lib/permissions\";\n\nfunction text(value: unknown) { return String(value ?? \"\").trim(); }\nfunction nullableText(value: unknown) { const raw = text(value); return raw || null; }\nfunction parseDate(value: unknown) {\n  const raw = text(value);\n  if (!raw) return null;\n  const date = new Date(raw);\n  return Number.isNaN(date.getTime()) ? null : date;\n}\nfunction recordStatus(value: unknown) {\n  const raw = text(value).toUpperCase();\n  if ([\"ACTIVE\", \"INACTIVE\", \"PENDING\", \"APPROVED\", \"REJECTED\", \"LOCKED\", \"CANCELLED\", \"DEDUCTED\", \"PARTIALLY_DEDUCTED\"].includes(raw)) return raw;\n  return undefined;\n}\nfunction serialize(value: unknown) { return JSON.parse(JSON.stringify(value ?? null)); }\nfunction canRead(request: Request) {\n  const role = roleFromHeaders(request.headers);\n  return canReadResource(role, \"driver-documents\") || canReadResource(role, \"drivers\");\n}\nfunction canWrite(request: Request) {\n  const role = roleFromHeaders(request.headers);\n  return canWriteResource(role, \"driver-documents\") || canWriteResource(role, \"drivers\");\n}\n\nexport async function GET(request: Request, context: { params: Promise<{ id: string }> | { id: string } }) {\n  if (!canRead(request)) return NextResponse.json({ error: \"Forbidden\" }, { status: 403 });\n  const params = await context.params;\n  const document = await prisma.driverDocument.findUnique({\n    where: { id: params.id },\n    include: { driver: { select: { id: true, name: true, actualName: true, internalCode: true } } },\n  });\n  if (!document) return NextResponse.json({ error: \"Not found\" }, { status: 404 });\n  return NextResponse.json({ document: serialize(document) });\n}\n\nexport async function PATCH(request: Request, context: { params: Promise<{ id: string }> | { id: string } }) {\n  if (!canWrite(request)) return NextResponse.json({ error: \"Forbidden\" }, { status: 403 });\n  const params = await context.params;\n  const before = await prisma.driverDocument.findUnique({ where: { id: params.id } });\n  if (!before) return NextResponse.json({ error: \"Not found\" }, { status: 404 });\n  const body = await request.json().catch(() => ({}));\n  const data: any = {};\n  if (body.driverId !== undefined) data.driverId = text(body.driverId);\n  if (body.type !== undefined) data.type = text(body.type) || before.type;\n  if (body.documentType !== undefined) data.documentType = nullableText(body.documentType);\n  if (body.documentNumber !== undefined) data.documentNumber = nullableText(body.documentNumber);\n  if (body.issueDate !== undefined) data.issueDate = parseDate(body.issueDate);\n  if (body.expiryDate !== undefined) data.expiryDate = parseDate(body.expiryDate);\n  if (body.status !== undefined) data.status = recordStatus(body.status) || before.status;\n  if (body.verificationStatus !== undefined) data.verificationStatus = text(body.verificationStatus) || before.verificationStatus;\n  if (body.fileUrl !== undefined) data.fileUrl = nullableText(body.fileUrl);\n  if (body.notes !== undefined) data.notes = nullableText(body.notes);\n\n  if (data.driverId) {\n    const driver = await prisma.driver.findUnique({ where: { id: data.driverId }, select: { id: true } });\n    if (!driver) return NextResponse.json({ error: \"\u0627\u0644\u0645\u0646\u062f\u0648\u0628 \u063a\u064a\u0631 \u0645\u0648\u062c\u0648\u062f.\" }, { status: 404 });\n  }\n\n  const document = await prisma.driverDocument.update({\n    where: { id: params.id },\n    data,\n    include: { driver: { select: { id: true, name: true, actualName: true, internalCode: true } } },\n  });\n\n  await prisma.auditLog.create({\n    data: {\n      user: request.headers.get(\"x-user-email\") || undefined,\n      action: \"UPDATE_DRIVER_DOCUMENT\",\n      entityType: \"DriverDocument\",\n      entityId: document.id,\n      oldValue: serialize(before),\n      newValue: serialize(document),\n    },\n  }).catch(() => null);\n\n  return NextResponse.json({ document: serialize(document) });\n}\n\nexport async function DELETE(request: Request, context: { params: Promise<{ id: string }> | { id: string } }) {\n  if (!canWrite(request)) return NextResponse.json({ error: \"Forbidden\" }, { status: 403 });\n  const params = await context.params;\n  const before = await prisma.driverDocument.findUnique({ where: { id: params.id } });\n  if (!before) return NextResponse.json({ ok: true, deleted: 0 });\n  await prisma.driverDocument.delete({ where: { id: params.id } });\n  await prisma.auditLog.create({\n    data: {\n      user: request.headers.get(\"x-user-email\") || undefined,\n      action: \"DELETE_DRIVER_DOCUMENT\",\n      entityType: \"DriverDocument\",\n      entityId: params.id,\n      oldValue: serialize(before),\n    },\n  }).catch(() => null);\n  return NextResponse.json({ ok: true, deleted: 1 });\n}\n";
files["scripts/check-rider-documents-module.cjs"] = "#!/usr/bin/env node\nconst fs = require('fs');\nconst path = require('path');\n\nconst root = process.cwd();\nlet failed = 0;\nfunction exists(rel) {\n  const ok = fs.existsSync(path.join(root, rel));\n  console.log(`${ok ? '\u2705' : '\u274c'} exists ${rel}`);\n  if (!ok) failed++;\n  return ok;\n}\nfunction contains(rel, needle, label = needle) {\n  const p = path.join(root, rel);\n  const ok = fs.existsSync(p) && fs.readFileSync(p, 'utf8').includes(needle);\n  console.log(`${ok ? '\u2705' : '\u274c'} ${rel}: ${label}`);\n  if (!ok) failed++;\n}\n\nconsole.log('\\nRider documents module check');\nconsole.log(`Project root: ${root}\\n`);\n\nexists('src/app/rider-documents/page.tsx');\nexists('src/components/rider-documents/RiderDocumentsClient.tsx');\nexists('src/lib/rider-documents/getRiderDocumentsData.ts');\nexists('src/app/api/rider-documents/route.ts');\nexists('src/app/api/rider-documents/[id]/route.ts');\n\nconsole.log('\\nContent checks');\ncontains('src/components/rider-documents/RiderDocumentsClient.tsx', '\u0645\u0633\u062a\u0646\u062f\u0627\u062a \u0627\u0644\u0645\u0646\u0627\u062f\u064a\u0628');\ncontains('src/components/rider-documents/RiderDocumentsClient.tsx', '\u062a\u0635\u062f\u064a\u0631 \u0625\u0643\u0633\u0644');\ncontains('src/components/rider-documents/RiderDocumentsClient.tsx', '\u0637\u0628\u0627\u0639\u0629 / PDF');\ncontains('src/components/rider-documents/RiderDocumentsClient.tsx', '+ \u0625\u0636\u0627\u0641\u0629 \u0645\u0633\u062a\u0646\u062f');\ncontains('src/components/rider-documents/RiderDocumentsClient.tsx', '\u062a\u0637\u0628\u064a\u0642');\ncontains('src/components/rider-documents/RiderDocumentsClient.tsx', '\u0639\u0631\u0636 \u0627\u0644\u0643\u0644');\ncontains('src/components/rider-documents/RiderDocumentsClient.tsx', '\u0627\u0639\u062a\u0645\u0627\u062f');\ncontains('src/components/rider-documents/RiderDocumentsClient.tsx', '\u0631\u0641\u0636');\ncontains('src/app/api/rider-documents/route.ts', 'export async function POST');\ncontains('src/app/api/rider-documents/[id]/route.ts', 'export async function PATCH');\ncontains('src/app/api/rider-documents/[id]/route.ts', 'export async function DELETE');\n\nconsole.log(`\\nRider documents module check result: ${failed ? 'FAILED' : 'OK'} | failed=${failed}`);\nprocess.exit(failed ? 1 : 0);\n";
files["scripts/smoke-rider-documents-crud.cjs"] = "#!/usr/bin/env node\nconst fs = require('fs');\nconst path = require('path');\nconst { PrismaClient } = require('@prisma/client');\n\nfunction loadDotEnv() {\n  const envPath = path.join(process.cwd(), '.env');\n  if (!fs.existsSync(envPath)) return;\n  for (const line of fs.readFileSync(envPath, 'utf8').split(/\\r?\\n/)) {\n    const trimmed = line.trim();\n    if (!trimmed || trimmed.startsWith('#')) continue;\n    const eq = trimmed.indexOf('=');\n    if (eq === -1) continue;\n    const key = trimmed.slice(0, eq).trim();\n    let value = trimmed.slice(eq + 1).trim();\n    if ((value.startsWith('\"') && value.endsWith('\"')) || (value.startsWith(\"'\") && value.endsWith(\"'\"))) value = value.slice(1, -1);\n    if (!process.env[key]) process.env[key] = value;\n  }\n}\nloadDotEnv();\n\nconst prisma = new PrismaClient();\nconst BASE_URL = process.env.ERP_BASE_URL || 'http://localhost:3040';\nconst EMAIL = process.env.ERP_TEST_EMAIL;\nconst PASSWORD = process.env.ERP_TEST_PASSWORD;\nconst QA = `qa-rider-documents-${Date.now()}`;\nlet failed = 0;\nconst created = { cityId: null, driverId: null, docId: null };\n\nfunction ok(label, extra='') { console.log(`\u2705 ${label}${extra ? ` \u2014 ${extra}` : ''}`); }\nfunction warn(label, extra='') { console.log(`\u26a0\ufe0f ${label}${extra ? ` \u2014 ${extra}` : ''}`); }\nfunction fail(label, extra='') { failed++; console.log(`\u274c ${label}${extra ? ` \u2014 ${extra}` : ''}`); }\nfunction statusOk(status) { return status >= 200 && status < 300; }\nfunction parseCookies(headers) {\n  const raw = headers.getSetCookie ? headers.getSetCookie() : [];\n  const fallback = headers.get('set-cookie') ? [headers.get('set-cookie')] : [];\n  return (raw.length ? raw : fallback)\n    .flatMap((v) => String(v).split(/,(?=[^;]+?=)/g))\n    .map((cookie) => cookie.split(';')[0])\n    .filter(Boolean)\n    .join('; ');\n}\nasync function requestJson(cookie, route, options={}) {\n  const res = await fetch(`${BASE_URL}${route}`, {\n    redirect: 'manual',\n    ...options,\n    headers: {\n      ...(options.body ? { 'content-type': 'application/json' } : {}),\n      ...(cookie ? { cookie } : {}),\n      ...(options.headers || {}),\n    },\n  });\n  const text = await res.text().catch(() => '');\n  let json = null;\n  try { json = text ? JSON.parse(text) : null; } catch {}\n  return { res, text, json };\n}\nasync function login() {\n  if (!EMAIL) throw new Error('ERP_TEST_EMAIL is required');\n  if (!PASSWORD) throw new Error('ERP_TEST_PASSWORD is required');\n  const { res, text } = await requestJson('', '/api/auth/login', { method: 'POST', body: JSON.stringify({ email: EMAIL, password: PASSWORD }) });\n  if (!statusOk(res.status)) throw new Error(`Login failed ${res.status}: ${text.slice(0, 300)}`);\n  const cookie = parseCookies(res.headers);\n  if (!cookie) throw new Error('Login did not return auth cookie');\n  return cookie;\n}\nasync function ensureDriver() {\n  let driver = await prisma.driver.findFirst({ select: { id: true, name: true, actualName: true, internalCode: true } }).catch(() => null);\n  if (driver) { ok('reference driver', driver.actualName || driver.name || driver.internalCode); return driver; }\n  const city = await prisma.city.create({ data: { nameAr: `\u0645\u062f\u064a\u0646\u0629 ${QA}`, nameEn: `City ${QA}`, status: 'ACTIVE' }, select: { id: true } });\n  created.cityId = city.id;\n  driver = await prisma.driver.create({\n    data: { internalCode: `DOC-${Date.now()}`, name: `\u0645\u0646\u062f\u0648\u0628 \u0627\u062e\u062a\u0628\u0627\u0631 ${QA}`, actualName: `\u0645\u0646\u062f\u0648\u0628 \u0627\u062e\u062a\u0628\u0627\u0631 ${QA}`, cityId: city.id, status: 'ACTIVE', source: 'qa-rider-documents' },\n    select: { id: true, name: true, actualName: true, internalCode: true },\n  });\n  created.driverId = driver.id;\n  ok('created QA driver', driver.actualName || driver.id);\n  return driver;\n}\nasync function cleanup() {\n  console.log('\\n4) Cleanup test records');\n  if (created.docId) await prisma.driverDocument.deleteMany({ where: { id: created.docId } }).then((r) => ok('cleanup document', String(r.count))).catch((e) => warn('cleanup document failed', e.message));\n  await prisma.driverDocument.deleteMany({ where: { documentNumber: { contains: QA } } }).catch(() => null);\n  if (created.driverId) await prisma.driver.deleteMany({ where: { id: created.driverId } }).then((r) => ok('cleanup driver', String(r.count))).catch((e) => warn('cleanup driver failed', e.message));\n  if (created.cityId) await prisma.city.deleteMany({ where: { id: created.cityId } }).then((r) => ok('cleanup city', String(r.count))).catch((e) => warn('cleanup city failed', e.message));\n}\n\nasync function main() {\n  console.log(`Rider documents CRUD smoke test: ${BASE_URL}`);\n  let cookie = '';\n  try {\n    cookie = await login();\n    ok('Login OK');\n    const driver = await ensureDriver();\n    console.log('\\n1) Page runtime');\n    const page = await fetch(`${BASE_URL}/rider-documents`, { headers: { cookie } });\n    const html = await page.text();\n    if (page.status === 200 && html.includes('\u0645\u0633\u062a\u0646\u062f\u0627\u062a \u0627\u0644\u0645\u0646\u0627\u062f\u064a\u0628')) ok('/rider-documents page', '200'); else fail('/rider-documents page', `status=${page.status}`);\n\n    console.log('\\n2) Create/update/delete document');\n    const expiry = new Date(); expiry.setDate(expiry.getDate() + 25);\n    const create = await requestJson(cookie, '/api/rider-documents', {\n      method: 'POST',\n      body: JSON.stringify({\n        driverId: driver.id,\n        type: 'iqama',\n        documentType: '\u0625\u0642\u0627\u0645\u0629',\n        documentNumber: QA,\n        issueDate: new Date().toISOString(),\n        expiryDate: expiry.toISOString(),\n        status: 'PENDING',\n        verificationStatus: 'pending',\n        notes: 'QA rider documents smoke',\n      }),\n    });\n    if (create.res.status === 201 && create.json?.document?.id) { created.docId = create.json.document.id; ok('POST /api/rider-documents', created.docId); } else fail('POST /api/rider-documents', `${create.res.status} ${create.text.slice(0, 200)}`);\n\n    if (created.docId) {\n      const patch = await requestJson(cookie, `/api/rider-documents/${created.docId}`, {\n        method: 'PATCH',\n        body: JSON.stringify({ status: 'APPROVED', verificationStatus: 'verified', notes: 'QA updated and verified' }),\n      });\n      if (statusOk(patch.res.status) && patch.json?.document?.verificationStatus === 'verified') ok('PATCH /api/rider-documents/:id', 'verified'); else fail('PATCH /api/rider-documents/:id', `${patch.res.status} ${patch.text.slice(0, 200)}`);\n\n      const list = await requestJson(cookie, `/api/rider-documents?q=${encodeURIComponent(QA)}`);\n      if (statusOk(list.res.status) && Array.isArray(list.json?.documents)) ok('GET /api/rider-documents?q=', `${list.json.documents.length} rows`); else fail('GET /api/rider-documents', `${list.res.status}`);\n\n      const del = await requestJson(cookie, `/api/rider-documents/${created.docId}`, { method: 'DELETE' });\n      if (statusOk(del.res.status)) { ok('DELETE /api/rider-documents/:id'); created.docId = null; } else fail('DELETE /api/rider-documents/:id', `${del.res.status} ${del.text.slice(0, 200)}`);\n    }\n  } catch (err) {\n    fail('Rider documents smoke crashed', err && err.message ? err.message : String(err));\n  } finally {\n    await cleanup();\n    await prisma.$disconnect();\n  }\n  console.log(`\\nRider documents CRUD result: ${failed ? 'FAILED' : 'OK'} | failed=${failed}`);\n  process.exit(failed ? 1 : 0);\n}\nmain();\n";
files["docs/RIDER_DOCUMENTS_MODULE_FIX.md"] = "# Rider Documents Module Fix\n\nAdds a complete `/rider-documents` operational page with filters, summary cards, CSV export, print, create/edit/approve/reject/delete actions and API routes.\n\nValidation:\n\n```bash\nnode scripts/check-rider-documents-module.cjs\nnode scripts/smoke-rider-documents-crud.cjs\n```\n";

